#!/usr/bin/env node
/**
 * Equipment-farming data generator.
 *
 * Fetches SchaleDB stages.json + equipment.json and writes a SLIM, bundled
 * constant of normal-campaign equipment drops to:
 *   src/lib/constants/equipmentDrops.ts
 *
 * Why bundle instead of fetching at runtime: the source stages.json is ~4 MB of
 * mostly combat data (formations, enemy lists, hex maps); the part we need is
 * ~7 KB. The data only changes when a new campaign area / equipment tier ships,
 * so a committed snapshot regenerated by hand is far cheaper than a 4 MB runtime
 * fetch + cache.
 *
 *   npm run build:equipment-drops      # re-run after SchaleDB content updates
 *
 * Filters applied:
 *   - Category === 'Campaign' && Difficulty === 0   (normal stages only)
 *   - ServerData.Global only                         (Global ≠ Cn drop rates)
 *   - Type === 'Equipment', no RewardType            (repeatable drops, not FirstClear/ThreeStar)
 *   - equipment Tier >= 2
 *
 * Drop "rate" = EXPECTED PIECES PER RUN, not a probability — it can exceed 1. A
 * stage lists the same equip id up to twice: an entry with no Chance is a
 * GUARANTEED drop (counts as 1.0), and an entry with a Chance is a bonus on top.
 * They must be SUMMED, e.g. 5-1 hairpin = 1.0 (guaranteed) + 0.2 (bonus) = 1.2.
 * (An earlier version wrongly treated the null-Chance entry as a dup of the
 * numbered one and kept only 0.2 — losing the guaranteed piece.)
 *
 * Random-pool (GachaGroup) drops: besides the tier-specific Equipment entries,
 * each higher stage carries "random equipment box" GachaGroup rewards (ids in
 * [600000,700000)) that resolve to a 2-tier pool of one category. The id minus
 * 600000 is the pool's upper-tier equippable id; the pool is {upper-1, upper}
 * weighted 1:2. We fold these into the stage's drops as expected counts
 * (chance×2/3 upper, chance×1/3 lower) so the farming hook can credit them as
 * byproducts — this is what makes our run counts match arona/justin (farming a
 * T10 stage also yields ~0.2 T8 + ~0.1 T7 per run, shrinking lower-tier farms).
 *
 * ID normalization: stages drop the 6-digit *crafting-material* id (e.g. 101001
 * = Hat T2 material), while the gear calc keys its "missing" needs to the 4-digit
 * *equippable* id (e.g. 1001 = Hat T2), derived from the recipe ingredient via
 * `parseInt(recipeId.substring(2))`. We apply the same strip here so a stage's
 * drop id matches the missing-equipment id the farming hook looks up.
 *
 * No runtime dependency — developer-only script. Language-independent: it stores
 * stage numbers + equip ids + chances; names/icons come from the app's cached
 * equipment data at render time.
 */
import { writeFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, resolve } from 'node:path';

const here = dirname(fileURLToPath(import.meta.url));
const OUT = resolve(here, '../src/lib/constants/equipmentDrops.ts');
const BASE = 'https://schaledb.com/data/en';

const fetchJson = async (url) => {
  const r = await fetch(url);
  if (!r.ok) throw new Error(`${url} → HTTP ${r.status}`);
  return r.json();
};

const [stages, equipment] = await Promise.all([
  fetchJson(`${BASE}/stages.json`),
  fetchJson(`${BASE}/equipment.json`),
]);

const tierOf = new Map(Object.entries(equipment).map(([k, v]) => [Number(k), v.Tier]));

const out = [];
for (const s of Object.values(stages)) {
  if (s.Category !== 'Campaign' || s.Difficulty !== 0) continue;
  const global = s.ServerData?.Global;
  if (!global) continue;

  const byId = new Map();
  for (const r of global.Rewards ?? []) {
    if (r.RewardType) continue;
    if (r.Type === 'Equipment') {
      // Normalize the 6-digit crafting-material id to the 4-digit equippable id
      // so it matches the gear calc's missing-equipment keys (see header note).
      const equipId = r.Id >= 100000 ? Number(String(r.Id).slice(2)) : r.Id;
      // Expected pieces per run: no Chance ⇒ guaranteed (1.0); a Chance is a bonus.
      // SUM the (possibly two) entries for this id — guaranteed + bonus.
      const expected = (r.Amount ?? 1) * (r.Chance ?? 1);
      byId.set(equipId, (byId.get(equipId) ?? 0) + expected);
    } else if (r.Type === 'GachaGroup' && r.Id >= 600000 && r.Id < 700000 && r.Chance != null) {
      // Random equipment box: a 2-tier pool of one category, weighted 1:2
      // (lower:upper). The group id minus 600000 is the equippable id of the pool's
      // UPPER tier (`top`); `top - 1` is the tier just below. Crediting these
      // byproducts is what lets farming a high-tier stage also chip away at
      // lower-tier needs — without them our run counts ran ~2-3× high vs arona/justin.
      const top = r.Id - 600000;
      byId.set(top, (byId.get(top) ?? 0) + r.Chance * (2 / 3));
      byId.set(top - 1, (byId.get(top - 1) ?? 0) + r.Chance * (1 / 3));
    }
  }
  // Keep only Tier >= 2 equippable drops (drops the T1 tail of the lowest pools).
  for (const id of [...byId.keys()]) {
    const tier = tierOf.get(id);
    if (!tier || tier < 2) byId.delete(id);
  }
  if (!byId.size) continue;

  const drops = [...byId.entries()]
    .sort((a, b) => (tierOf.get(b[0]) ?? 0) - (tierOf.get(a[0]) ?? 0)) // high tier first
    .map(([equipId, rate]) => ({ equipId, rate: +rate.toFixed(4) }));
  out.push({ id: s.Id, area: s.Area, stage: s.Stage, ap: s.EntryCost?.[0]?.[1] ?? 0, drops });
}
out.sort((a, b) => a.area - b.area || a.stage - b.stage);

const rows = out
  .map(
    (st) =>
      `  { id: ${st.id}, area: ${st.area}, stage: ${st.stage}, ap: ${st.ap}, drops: [${st.drops
        .map((d) => `{ equipId: ${d.equipId}, rate: ${d.rate} }`)
        .join(', ')}] },`,
  )
  .join('\n');

const file = `// AUTO-GENERATED by scripts/build-equipment-drops.mjs — do not edit by hand.
// Regenerate with \`npm run build:equipment-drops\` after SchaleDB content updates.
// Source: normal campaign stages (Difficulty 0, ServerData.Global), equipment
// drops Tier >= 2. Generated ${new Date().toISOString().slice(0, 10)}.

export interface FarmStageDrop {
  /** Equipment id — matches equipment.json / the gear store. */
  equipId: number;
  /** Expected pieces per run = guaranteed (1.0 if always dropped) + bonus
   *  chances, summed. May exceed 1 (e.g. 1.2). Before any 2x/3x multiplier. */
  rate: number;
}

export interface FarmStage {
  id: number;
  /** Campaign area + stage, rendered as \`area-stage\` (e.g. "4-1"). */
  area: number;
  stage: number;
  /** AP cost per run (uniform 10 for repeatable equipment stages). */
  ap: number;
  /** Tier >= 2 equipment drops (tier-specific + folded-in random-pool
   *  byproducts), highest tier first. */
  drops: FarmStageDrop[];
}

export const EQUIPMENT_FARM_STAGES: FarmStage[] = [
${rows}
];
`;

writeFileSync(OUT, file);
console.log(`wrote ${OUT} — ${out.length} normal stages with Tier 2+ equipment drops`);
